import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [role, setRole] = useState(null);
  const [students, setStudents] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedFasal, setSelectedFasal] = useState("Dhamaan");
  const [currentUser, setCurrentUser] = useState(null);

  const fasalList = ["Fasalka 1", "Fasalka 2", "Fasalka 3", "Fasalka 4", "Fasalka 5", "Fasalka 6", "Fasalka 7", "Fasalka 8", "Form 1", "Form 2", "Form 3", "Form 4"];

  useEffect(() => {
    if (role === 'admin') axios.get('http://localhost:3000/admin/students').then(res => setStudents(res.data));
  }, [role]);

  // SEARCH & FILTER LOGIC
  const filtered = students.filter(s => 
    (selectedFasal === "Dhamaan" || s.fasalka === selectedFasal) &&
    s.magaca.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const AdminView = () => (
    <div style={{ padding: '20px' }}>
      <h2>💻 Dashboard-ka Maamulka</h2>
      <div style={{ background: '#fff', padding: '15px', borderRadius: '10px', marginBottom: '20px' }}>
        <input type="text" placeholder="🔍 Raadi magaca ardayga..." style={{padding: '10px', width: '300px', marginRight: '10px'}} onChange={e => setSearchTerm(e.target.value)} />
        <select onChange={e => setSelectedFasal(e.target.value)} style={{padding: '10px'}}>
          <option value="Dhamaan">Dhamaan Fasallada</option>
          {fasalList.map(f => <option key={f} value={f}>{f}</option>)}
        </select>
      </div>
      <table border="1" width="100%" style={{ borderCollapse: 'collapse', background: 'white' }}>
        <thead style={{ background: '#2c3e50', color: 'white' }}>
          <tr><th>ID</th><th>Magaca</th><th>Fasalka</th><th>Dhibcaha</th></tr>
        </thead>
        <tbody>
          {filtered.map(s => (
            <tr key={s.id} style={{ textAlign: 'center' }}>
              <td>{s.id}</td><td>{s.magaca}</td><td>{s.fasalka}</td>
              <td><input type="number" value={s.dhibcaha} onChange={e => axios.put(`http://localhost:3000/admin/update-student/${s.id}`, {dhibcaha: e.target.value})} /></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  if (!role) {
    return (
      <div style={{ textAlign: 'center', marginTop: '100px' }}>
        <h1>Dugsi Management System</h1>
        <button onClick={() => {
          const p = prompt("Password-ka Admin:");
          axios.post('http://localhost:3000/login', { type: 'admin', password: p }).then(() => setRole('admin')).catch(() => alert("Khalad!"));
        }}>Geli Maamule</button>

        <button onClick={() => {
          const f = prompt("Dooro Fasalkaaga (Tusaale: Form 4):");
          const id = prompt("Geli ID-gaaga:");
          const p = prompt("Geli Password (1234):");
          axios.post('http://localhost:3000/login', { type: 'student', id, password: p, fasalka: f })
            .then(res => { setCurrentUser(res.data); setRole('student'); }).catch(() => alert("Xogtaada lama helin!"));
        }}>Geli Arday</button>
      </div>
    );
  }

  return (
    <div style={{ background: '#f0f2f5', minHeight: '100vh' }}>
      <button onClick={() => setRole(null)} style={{margin: '10px', background: 'red', color: 'white'}}>Logout</button>
      {role === 'admin' ? <AdminView /> : <div style={{textAlign: 'center'}}><h2>Natiijada: {currentUser.dhibcaha}%</h2></div>}
    </div>
  );
}

export default App;
